```class Solution {
public:
    bool isSubstringPresent(string s) {
        string rev_s = s;
        reverse(rev_s.begin(), rev_s.end());
        for (int i = 0; i < s.size() - 1; i++) {
            string substr = s.substr(i, 2);
            if (rev_s.find(substr) != string::npos) {
                return true;
            }
        }
        return false;
    }
};
